function report = runIdenticalBandGroupingBenchmark(options)
%RUNIDENTICALBANDGROUPINGBENCHMARK Measure exact-grid row-band reuse.
%
% Adjacent tiles share one physical label vector. The grouped run merges only
% horizontally contiguous, bit-identical grids; the ungrouped run is the
% numerical reference. No scientific cost or height-selection setting changes.
%
% Traceability: algo/main.tex Algorithm 1, lines 4--9; implementation plan
% C1 milestone 5, identical-band grouping control.

arguments
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [192, 224]
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [48, 56]
    options.HeightLabelsMetres (1, :) double ...
        {mustBeFinite, mustBeIncreasingLabels, mustHaveThreeLabels} = ...
        linspace(-4, 10, 7)
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.MaximumBandTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.Repetitions (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 5
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ["single", "double"])} = ...
        "single"
    options.UseParallel (1, 1) logical = false
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.Verbose (1, 1) logical = true
end

renderer = SyntheticPinholeRenderer("identical-band-benchmark", ...
    options.ImageSize, MeanObliquityDegrees=60, ConvergenceDegrees=2, ...
    TrueHeightMetres=3, TextureSeed=719);
pair = renderer.renderPair;
levels = cast(2 ^ renderer.BitDepth - 1, options.WorkingPrecision);
reference = cast(pair.ReferenceImage, options.WorkingPrecision) ./ levels;
moving = cast(pair.MovingImage, options.WorkingPrecision) ./ levels;
geometry = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
curve = HeightCostCurve(geometry, reference, moving, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid, ...
    PrepareGradients=false, WorkingPrecision=options.WorkingPrecision);
dense = DenseHeightSweep(curve);
plan = makePlan(options.ImageSize, options.TileSize, ...
    options.HeightLabelsMetres);
common = { ...
    "LabelBlockSize", options.LabelBlockSize, ...
    "StoreCostVolumes", true, ...
    "MaximumBandTiles", options.MaximumBandTiles, ...
    "UseParallel", options.UseParallel, ...
    "NumWorkers", options.NumWorkers, ...
    "WorkingPrecision", options.WorkingPrecision};

dense.runZnccPlannedTiles(plan, common{:}, GroupIdenticalBands=false);
dense.runZnccPlannedTiles(plan, common{:}, GroupIdenticalBands=true);
ungroupedSeconds = zeros(options.Repetitions, 1);
groupedSeconds = zeros(options.Repetitions, 1);
for k = 1:options.Repetitions
    if mod(k, 2) == 1
        timer = tic;
        ungrouped = dense.runZnccPlannedTiles( ...
            plan, common{:}, GroupIdenticalBands=false);
        ungroupedSeconds(k) = toc(timer);
        timer = tic;
        grouped = dense.runZnccPlannedTiles( ...
            plan, common{:}, GroupIdenticalBands=true);
        groupedSeconds(k) = toc(timer);
    else
        timer = tic;
        grouped = dense.runZnccPlannedTiles( ...
            plan, common{:}, GroupIdenticalBands=true);
        groupedSeconds(k) = toc(timer);
        timer = tic;
        ungrouped = dense.runZnccPlannedTiles( ...
            plan, common{:}, GroupIdenticalBands=false);
        ungroupedSeconds(k) = toc(timer);
    end
end

maximumCostDelta = 0;
for k = 1:height(plan)
    a = double(grouped.CostVolumesByTile{k});
    b = double(ungrouped.CostVolumesByTile{k});
    finite = isfinite(a) & isfinite(b);
    if any(finite, "all")
        maximumCostDelta = max( ...
            maximumCostDelta, max(abs(a(finite) - b(finite))));
    end
end
if options.WorkingPrecision == "single"
    tolerance = 8 .* eps("single");
else
    tolerance = 2e-12;
end
ungroupedMedian = median(ungroupedSeconds);
groupedMedian = median(groupedSeconds);
summary = table( ...
    ["ungrouped"; "grouped"], ...
    [ungroupedMedian; groupedMedian], ...
    [ungrouped.Runtime.BandCount; grouped.Runtime.BandCount], ...
    [ungrouped.Runtime.WarpCalls; grouped.Runtime.WarpCalls], ...
    [ungrouped.Runtime.WarpPointEvaluations; ...
    grouped.Runtime.WarpPointEvaluations], ...
    VariableNames=["Mode", "MedianSeconds", "BandCount", ...
    "WarpCalls", "WarpPointEvaluations"]);
report = struct( ...
    "Summary", summary, ...
    "UngroupedSeconds", ungroupedSeconds, ...
    "GroupedSeconds", groupedSeconds, ...
    "Speedup", ungroupedMedian ./ groupedMedian, ...
    "TileCount", height(plan), ...
    "UngroupedBandCount", ungrouped.Runtime.BandCount, ...
    "GroupedBandCount", grouped.Runtime.BandCount, ...
    "MaximumCostDelta", maximumCostDelta, ...
    "CostTolerance", tolerance, ...
    "LabelDisagreementCount", ...
    nnz(grouped.LabelIndex ~= ungrouped.LabelIndex), ...
    "ValidityEqual", isequal(grouped.Valid, ungrouped.Valid), ...
    "Pass", maximumCostDelta <= tolerance ...
    && isequal(grouped.LabelIndex, ungrouped.LabelIndex) ...
    && isequal(grouped.Valid, ungrouped.Valid), ...
    "Plan", plan, ...
    "Policy", ...
    "merge only horizontally contiguous tiles with bit-identical physical labels", ...
    "WorkingPrecision", options.WorkingPrecision, ...
    "Execution", "CPU row-band grouping control");
if options.Verbose
    disp(summary)
    fprintf("Speedup: %.3fx\n", report.Speedup);
    fprintf("Maximum cost delta: %.9g (tolerance %.9g); " + ...
        "label disagreements: %d\n", maximumCostDelta, tolerance, ...
        report.LabelDisagreementCount);
end
end

function plan = makePlan(imageSize, tileSize, z)
rowStarts = 1:tileSize(1):imageSize(1);
columnStarts = 1:tileSize(2):imageSize(2);
rows = cell(numel(rowStarts) .* numel(columnStarts), 8);
tile = 0;
for rowStart = rowStarts
    for columnStart = columnStarts
        tile = tile + 1;
        rowEnd = min(rowStart + tileSize(1) - 1, imageSize(1));
        columnEnd = min( ...
            columnStart + tileSize(2) - 1, imageSize(2));
        rows(tile, :) = {tile, rowStart, rowEnd, ...
            columnStart, columnEnd, ...
            (rowEnd - rowStart + 1) .* (columnEnd - columnStart + 1), ...
            numel(z), {double(z)}};
    end
end
plan = cell2table(rows, VariableNames=["Tile", "RowStart", "RowEnd", ...
    "ColumnStart", "ColumnEnd", "PixelCount", "LabelCount", ...
    "HeightLabelsMetres"]);
end

function mustHaveThreeLabels(z)
if numel(z) < 3
    error("BandGroupingBenchmark:TooFewLabels", ...
        "HeightLabelsMetres must contain at least three labels.");
end
end

function mustBeIncreasingLabels(z)
if any(diff(z) <= 0)
    error("BandGroupingBenchmark:LabelsNotIncreasing", ...
        "HeightLabelsMetres must be strictly increasing.");
end
end
